// -----------------------------------------------------------------------------
// HANDWRITTEN TOOL SCRIPT
//
// File       : dev/tools/docs/doc.bundleAll.js
// Purpose    : Bundle key documentation files into a single markdown file for
//              easy review and sharing.
// Writes     : docs/internal/bundle.docs.md
// Reads      : A curated list of markdown files from root and docs/.
// Notes      : Skips missing files gracefully; uses shared generator logger.
// -----------------------------------------------------------------------------

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { createStepLogger } from '../../generators/_logger.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname  = path.dirname(__filename);

// Project root = three levels up from /dev/tools/docs
const PROJECT_ROOT = path.resolve(__dirname, '..', '..', '..');

// Where the bundle is written
const BUNDLE_PATH = path.join(
  PROJECT_ROOT,
  'docs',
  'internal',
  'bundle.docs.md',
);

// Curated list of docs to include, in order.
// NOTE: Missing files are skipped with a "skip" log entry.
const DOCS_TO_INCLUDE = [
  { label: 'Root README',                          relPath: 'README.md' },
  { label: 'Docs index',                           relPath: 'docs/README.md' },
  { label: 'Backend docs index',                   relPath: 'docs/backend/README.md' },
  { label: 'Backend architecture overview',        relPath: 'docs/backend/architecture/overview.md' },
  { label: 'Backend generators',                   relPath: 'docs/backend/generators.md' },
  { label: 'Backend OpenAPI',                      relPath: 'docs/backend/openapi.md' },
  { label: 'Backend generated docs index',         relPath: 'docs/backend/generated/README.md' },
  { label: 'Backend manual API docs placeholder',  relPath: 'docs/backend/manual/README.md' },
  { label: 'Backend testing overview',             relPath: 'docs/backend/testing/README.md' },
  { label: 'Style guide',                          relPath: 'docs/style/README.md' },
  { label: 'Contributing',                         relPath: 'CONTRIBUTING.md' },
  { label: 'Changelog',                            relPath: 'CHANGELOG.md' },
];

// Create logger (prints banner immediately)
const log = createStepLogger({
  step: 'docs',
  title: 'Bundle Documentation',
  generatorPath: 'dev/tools/docs/doc.bundleAll.js',
  projectRoot: PROJECT_ROOT,
});

// -----------------------------------------------------------------------------
// Helpers
// -----------------------------------------------------------------------------

function readDocOrSkip(doc) {
  const absPath = path.resolve(PROJECT_ROOT, doc.relPath);

  if (!fs.existsSync(absPath)) {
    log.write(`skip     : ${doc.relPath} (missing)`);
    return null;
  }

  const raw = fs.readFileSync(absPath, 'utf8');

  // Wrap each doc with clear markers so we know where content came from.
  const wrapped = [
    `<!-- DOC-BEGIN: ${doc.relPath} (${doc.label}) -->`,
    '',
    raw.trimEnd(),
    '',
    `<!-- DOC-END: ${doc.relPath} (${doc.label}) -->`,
    '',
  ].join('\n');

  return wrapped;
}

function ensureDirForFile(absPath) {
  const dir = path.dirname(absPath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
}

// -----------------------------------------------------------------------------
// Main
// -----------------------------------------------------------------------------

function main() {
  try {
    log.kv('root', PROJECT_ROOT);
    log.kv('output', path.relative(PROJECT_ROOT, BUNDLE_PATH));
    log.kv('docs.count', String(DOCS_TO_INCLUDE.length));

    const chunks = [];

    // Header for the bundle itself
    const headerLines = [
      '# Documentation Bundle',
      '',
      '> Combined view of key documentation files for review.',
      '> This file is auto-generated by dev/tools/docs/doc.bundleAll.js.',
      '',
      '---',
      '',
    ];
    chunks.push(headerLines.join('\n'));

    for (const doc of DOCS_TO_INCLUDE) {
      const content = readDocOrSkip(doc);
      if (content) {
        chunks.push(content);
      }
    }

    const bundleContent = chunks.join('\n').trimEnd() + '\n';

    ensureDirForFile(BUNDLE_PATH);
    fs.writeFileSync(BUNDLE_PATH, bundleContent, 'utf8');

    const relBundle = path.relative(PROJECT_ROOT, BUNDLE_PATH) || BUNDLE_PATH;
    log.write(`report   : bundled docs → ${relBundle}`);

    log.success();
  } catch (err) {
    log.failure(err);
    process.exit(1);
  }
}

main();

// -----------------------------------------------------------------------------
// End of tool script: doc.bundleAll
// -----------------------------------------------------------------------------
